previewCss:
.darma-loader-linear-progress {
  position: relative;
  display: inline-block;
  width: 132px;
  height: 10px;
  overflow: hidden;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 15%, transparent);
}
.darma-loader-linear-progress::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 48%;
  border-radius: inherit;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-linear-progress-progress 1.25s ease-in-out infinite;
}
@keyframes darma-loader-linear-progress-progress {
  0% { transform: translateX(-105%); }
  55%, 100% { transform: translateX(210%); }
}

